import { useEffect, useMemo, useRef, useState } from "react";

export default function Index() {
  const sections = useMemo(
    () => [
      {
        id: "objective",
        title: "Objective",
        body: (
          <p className="text-orbis-t2/90 leading-relaxed">
            Orbis Empresarial preserves, organizes, and showcases the corporate heritage of Bolivian
            companies with more than 40 years of trajectory. We digitize archives, certify milestones,
            and curate living narratives that honor legacy while inspiring the next generation of leaders.
          </p>
        ),
      },
      {
        id: "mission",
        title: "Mission",
        body: (
          <p className="text-orbis-t2/90 leading-relaxed">
            To protect the memory of Bolivian enterprise through rigorous documentation, thoughtful
            storytelling, and timeless design—making each company’s journey accessible, verifiable, and
            beautifully preserved for the future.
          </p>
        ),
      },
      {
        id: "vision",
        title: "Vision",
        body: (
          <p className="text-orbis-t2/90 leading-relaxed">
            A prestigious national archive where the history of business excellence is treasured—
            a reference for researchers, entrepreneurs, and families that elevates the legacy of
            Bolivian industry on the world stage.
          </p>
        ),
      },
      {
        id: "origin",
        title: "Origin",
        body: (
          <p className="text-orbis-t2/90 leading-relaxed">
            Born from a commitment to cultural memory, Orbis Empresarial emerged when historians,
            archivists, and innovators united around a single idea: if we don’t document our
            enterprises today, tomorrow’s generations will inherit silence where there should be legacy.
          </p>
        ),
      },
      {
        id: "how",
        title: "How it started",
        body: (
          <div className="w-full">
            <div className="relative overflow-x-auto md:overflow-visible px-2 py-6">
              <div className="absolute left-6 right-6 md:left-8 md:right-8 top-1/2 -translate-y-1/2 h-[3px] bg-gradient-to-r from-orbis-beige/60 via-orbis-accent/70 to-orbis-navy/60 rounded-full" />
              <ol className="relative z-10 flex min-w-[640px] md:min-w-0 items-start gap-10 md:gap-12 lg:gap-16 px-4 md:px-8 snap-x">
                {[
                  { year: "1980s", text: "Foundational archives collected across departments." },
                  { year: "1990s", text: "First private–public preservation partnerships." },
                  { year: "2000s", text: "Digitization program and certification standards." },
                  { year: "2010s", text: "Interactive exhibits and institutional expansion." },
                  { year: "Today", text: "A living platform connecting legacy with innovation." },
                ].map((m) => (
                  <li key={m.year} className="snap-center min-w-[160px]">
                    <div className="flex flex-col items-center text-center gap-3">
                      <div className="relative">
                        <span className="block w-3 h-3 rounded-full bg-orbis-accent shadow-[0_0_0_6px_hsl(var(--orbis-accent)/0.2)]" />
                        <span className="pointer-events-none absolute -inset-3 rounded-full bg-[radial-gradient(circle_at_center,hsl(var(--orbis-accent)/0.45),transparent_60%)] blur-md animate-glow" />
                      </div>
                      <div className="text-sm font-medium tracking-wide text-orbis-t1/90">
                        <span className="font-serif-display text-xl text-orbis-t1 block">{m.year}</span>
                        <span className="text-orbis-t2/80 block max-w-[16rem]">{m.text}</span>
                      </div>
                    </div>
                  </li>
                ))}
              </ol>
            </div>
          </div>
        ),
      },
    ],
    [],
  );

  const [active, setActive] = useState(sections[0].id);
  const [visible, setVisible] = useState({});
  const refs = useRef({});

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        let best = { id: active, ratio: 0 };
        entries.forEach((entry) => {
          const id = entry.target.id;
          if (entry.isIntersecting) {
            setVisible((prev) => ({ ...prev, [id]: true }));
          }
          if (entry.intersectionRatio > best.ratio) {
            best = { id, ratio: entry.intersectionRatio };
          }
        });
        if (best.id) setActive(best.id);
      },
      { root: null, threshold: [0.25, 0.5, 0.75], rootMargin: "-20% 0px -40% 0px" },
    );

    sections.forEach((s) => {
      const el = refs.current[s.id];
      if (el) observer.observe(el);
    });
    return () => observer.disconnect();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const scrollTo = (id) => {
    const el = refs.current[id];
    if (!el) return;
    el.scrollIntoView({ behavior: "smooth", block: "start" });
    setActive(id);
  };

  return (
    <div className="min-h-screen bg-orbis-page text-orbis-t1 selection:bg-orbis-accent/20">
      {/* subtle animated gradient backdrop */}
      <div aria-hidden className="pointer-events-none fixed inset-0 -z-10 bg-[radial-gradient(1200px_600px_at_-10%_-10%,hsl(var(--orbis-beige)/0.35),transparent_60%),radial-gradient(900px_600px_at_110%_110%,hsl(var(--orbis-navy)/0.4),transparent_60%)] animate-gradient-x" />

      <main className="mx-auto max-w-[1400px] px-4 sm:px-6 lg:px-10 py-6 sm:py-10">
        {/* Mobile top bar */}
        <div className="md:hidden sticky top-0 z-20 -mx-4 px-4 py-3 backdrop-blur bg-white/70 border-b border-orbis-t5/50">
          <div className="flex gap-3 overflow-x-auto no-scrollbar">
            {sections.map((s) => (
              <button
                key={s.id}
                onClick={() => scrollTo(s.id)}
                className={`whitespace-nowrap rounded-full px-4 py-2 text-sm tracking-wide transition relative nav-glow ${
                  active === s.id
                    ? "text-orbis-accent ring-1 ring-orbis-accent/50"
                    : "text-orbis-t2 hover:text-orbis-accent"
                }`}
              >
                {s.title}
              </button>
            ))}
          </div>
        </div>

        {/* Desktop layout */}
        <div className="grid md:grid-cols-[minmax(220px,18%)_1fr] gap-6 lg:gap-10">
          {/* Left nav */}
          <aside className="hidden md:flex sticky top-6 h-[calc(100vh-3rem)] flex-col justify-between border-r border-orbis-t5/60 pr-6 lg:pr-8">
            <div>
              <h1 className="font-serif-display text-3xl lg:text-4xl text-orbis-t1 tracking-tight">
                Orbis Empresarial
              </h1>
              <div className="mt-2 h-[3px] w-16 bg-orbis-accent rounded-full" />
              <p className="mt-4 text-sm text-orbis-t2/90">
                Preserving the living history of Bolivian companies 40+ years strong.
              </p>

              <nav className="mt-8 flex flex-col gap-2">
                {sections.map((s) => (
                  <button
                    key={s.id}
                    onClick={() => scrollTo(s.id)}
                    className={`group nav-item nav-glow text-left px-3 py-2 rounded-md transition relative ${
                      active === s.id
                        ? "text-orbis-accent bg-white/40 ring-1 ring-orbis-accent/40"
                        : "text-orbis-t2 hover:text-orbis-accent"
                    }`}
                  >
                    <span className="inline-flex items-center gap-3">
                      <span
                        className={`inline-block h-1.5 w-1.5 rounded-full transition-all ${
                          active === s.id ? "bg-orbis-accent scale-100" : "bg-orbis-t4 scale-75"
                        }`}
                      />
                      <span className="uppercase tracking-wider text-xs lg:text-sm">
                        {s.title}
                      </span>
                    </span>
                  </button>
                ))}
              </nav>
            </div>

            <div className="hidden lg:block text-xs text-orbis-t3/80">
              © {new Date().getFullYear()} Orbis Empresarial
            </div>
          </aside>

          {/* Right content */}
          <section className="flex flex-col gap-8 lg:gap-12">
            {sections.map((s, idx) => (
              <div
                key={s.id}
                id={s.id}
                ref={(el) => (refs.current[s.id] = el)}
                className="scroll-mt-28 md:scroll-mt-14"
              >
                {/* Card with animated gradient border */}
                <div
                  className={`group relative rounded-2xl p-[1px] transition-transform duration-300 ${
                    visible[s.id] ? "translate-y-0 opacity-100" : "translate-y-6 opacity-0"
                  }`}
                  style={{ transitionProperty: "transform, opacity" }}
                >
                  <div className="absolute -inset-10 -z-10 opacity-40">
                    {/* blurred decorative blobs */}
                    <div className="absolute -top-6 -left-6 w-56 h-56 rounded-full bg-[radial-gradient(circle_at_top_left,hsl(var(--orbis-beige)/0.6),transparent_55%)] blur-2xl animate-float" />
                    <div className="absolute -bottom-8 -right-8 w-72 h-72 rounded-full bg-[radial-gradient(circle_at_bottom_right,hsl(var(--orbis-navy)/0.45),transparent_50%)] blur-3xl animate-gradient-x" />
                  </div>

                  <div className="rounded-2xl bg-gradient-to-br from-[hsl(var(--orbis-beige)/0.9)] via-white/70 to-[hsl(var(--orbis-navy)/0.35)]">
                    <div className="relative rounded-2xl bg-white/70 backdrop-blur-xl p-6 sm:p-8 lg:p-12 shadow-[0_10px_30px_rgba(7,45,66,0.15)]">
                      <header className="mb-4 sm:mb-6">
                        <h2 className="font-serif-display text-2xl sm:text-3xl lg:text-4xl text-orbis-t1">
                          {s.title}
                        </h2>
                        <div className="mt-2 h-[3px] w-14 bg-orbis-accent rounded-full transition-all group-hover:w-20" />
                      </header>
                      <div className="prose prose-neutral max-w-none text-base sm:text-lg text-orbis-t1/90">
                        {s.body}
                      </div>
                    </div>
                  </div>
                </div>

                {/* Subtle section separator using gradient */}
                {idx !== sections.length - 1 && (
                  <div className="mt-8 h-px bg-gradient-to-r from-transparent via-orbis-t5/70 to-transparent" />
                )}
              </div>
            ))}
          </section>
        </div>
      </main>
    </div>
  );
}
